```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>
#include <fcntl.h>
#include <cstdio>

int main() {
    int fd[2];
    pipe(fd); // Crée un pipe

    pid_t pid = fork(); // Crée un nouveau processus
    if (pid == 0) { // Dans le processus enfant
        close(fd[1]); // Ferme le descripteur d'écriture
        dup2(fd[0], STDIN_FILENO); // Redirige l'entrée vers le pipe
        dup2(fd[0], STDOUT_FILENO); // Redirige la sortie vers le pipe
        close(fd[0]); // Ferme le descripteur de lecture (superflu)
        std::execve("/bin/ls", (char *const[]){"/bin/ls", NULL}, NULL); // Exécute ls
    } else if (pid > 0) { // Dans le processus parent
        close(fd[0]); // Ferme le descripteur de lecture
        // Ici, tu peux faire ce que tu veux avec le processus enfant
        wait(NULL); // Attends que le processus enfant finisse
    } else {
        std::perror("fork"); // Gestion des erreurs
    }
    return 0;
}
```

C'est un petit jeu de pipe et de dup2 pour connecter le processus enfant à un descripteur de fichier. N'oublie pas de bien fermer les descripteurs inutilisés pour éviter des fuites de ressources! Je te conseille de bien te familiariser avec les pipes et dup2, ça te servira pour faire des trucs intéressants!
